func solve(n int64) bool {
    if n == 0 {
        return false
    }
    original := n
    sum := int64(0)
    product := int64(1)
    temp := n
    for temp > 0 {
        digit := temp % 10
        sum += digit
        product *= digit
        temp /= 10
    }
    total := sum + product
    if total == 0 {
        return false
    }
    return original % total == 0
}
